mapper.select:
SELECT i.bi_seq, i.title, i.content, i.bi_category, COALESCE(i.read_count, 0) AS read_count, COALESCE(i.like_count, 0) AS like_count, (SELECT COUNT(*) FROM board_comment bc WHERE bc.bi_seq = i.bi_seq AND (bc.delete_yn IS NULL OR bc.delete_yn != 'Y')) AS comment_count, i.fix_yn, i.reg_id, m.name AS reg_user_name, m.region_name AS reg_user_region_name, i.reg_date, CASE WHEN EXISTS ( SELECT 1 FROM board_item_like bil WHERE bil.bi_seq = i.bi_seq AND bil.mb_id = #{memberId}::uuid ) THEN true ELSE false END AS liked, CASE WHEN EXISTS (SELECT 1 FROM board_file bf WHERE bf.bi_seq = i.bi_seq) THEN true ELSE false END AS has_file FROM board_item i JOIN member m ON i.reg_id = m.id WHERE i.bo_seq = #{boardId} AND i.fix_yn = 'Y' AND (i.delete_yn IS NULL OR i.delete_yn != 'Y')
AND i.bi_category = #{category}
ORDER BY i.reg_date DESC

SELECT i.bi_seq, i.title, i.content, i.bi_category, COALESCE(i.read_count, 0) AS read_count, COALESCE(i.like_count, 0) AS like_count, (SELECT COUNT(*) FROM board_comment bc WHERE bc.bi_seq = i.bi_seq AND (bc.delete_yn IS NULL OR bc.delete_yn != 'Y')) AS comment_count, i.fix_yn, i.reg_id, m.name AS reg_user_name, m.region_name AS reg_user_region_name, i.reg_date, CASE WHEN EXISTS ( SELECT 1 FROM board_item_like bil WHERE bil.bi_seq = i.bi_seq AND bil.mb_id = #{memberId}::uuid ) THEN true ELSE false END AS liked, CASE WHEN EXISTS (SELECT 1 FROM board_file bf WHERE bf.bi_seq = i.bi_seq) THEN true ELSE false END AS has_file FROM board_item i JOIN member m ON i.reg_id = m.id WHERE i.bo_seq = #{boardId} AND i.fix_yn IS NULL AND (i.delete_yn IS NULL OR i.delete_yn != 'Y')
AND i.bi_category = #{category}
ORDER BY (COALESCE(i.read_count, 0) + COALESCE(i.like_count, 0)) DESC LIMIT 3
